function ecAff_isOnCurve(uint256 x, uint256 y) internal pure returns (bool) {
    if (((0 == x) && (0 == y)) || x == p || y == p) {
        return false;
    }
    unchecked {
        uint256 LHS = mulmod(y, y, p); // y^2
        uint256 RHS = addmod(mulmod(mulmod(x, x, p), x, p), mulmod(x, a, p), p); // x^3+ax
        RHS = addmod(RHS, b, p); // x^3 + a*x + b

        return LHS == RHS;
